custom_css:
/* Estilo de Páscoa para a sua classe */
.minha-logo { 
    font-size: 30px; 
    font-weight: 900; 
    font-style: italic;
    color: #ffb7ce; /* Rosa Pastel */
    text-shadow: 2px 2px 0px #ffffff, 0 0 15px rgba(255, 183, 206, 0.4);
    letter-spacing: -1px;
    animation: bounce 2s infinite ease-in-out;
}

/* Cor do STUDIO */
.minha-logo span { 
    color: #b2e2f2; /* Azul Pastel */
    text-shadow: 2px 2px 0px #ffffff;
}

/* Animação de pulinho do coelho */
@keyframes bounce {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-6px); }
}
